SELECT COUNT(DISTINCT S.PK_SIAPE) AS QUANTIDADE FROM CALC_HORA_AULA_MEDIA CHM JOIN SERVIDOR S ON S.PK_SIAPE = CHM.SIAPE WHERE CHM.ANO = 2024 AND CHM.SEMESTRE = 2 AND CHM.SIGLA_CAMPUS = 'ITU' AND LOWER(COALESCE(S.CONTRATO, '')) = 'efetivos' AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%sociologia%'